return {{date="2026-01-28",author="CrazySpottedDove",message="初步支持了tsv波次文件；修复了五代死法的纹理错误；修复了五代死法攻击大眼导致蓝屏的问题；修复大量五代敌人移速机制未生效问题；添加了暗钢矮人支线。出于一些原因，诡须的封塔从手动解封改为了随时间随机解封。"},{date="2026-01-28",author="CrazySpottedDove",message="取消五代前3关英雄钢铁模式对英雄携带的限制"},{date="2026-01-28",author="CrazySpottedDove",message="略微削弱矮人支线敌人的生命值"},{date="2026-01-28",author="CrazySpottedDove",message="增大空间索引缓冲区；修复防御塔按钮位置反了的问题"},{date="2026-01-29",author="CrazySpottedDove",message="修复血壤巨兽攻击时卡死的问题"},{date="2026-01-29",author="CrazySpottedDove",message="优化了局内ui的性能；使局内ui不受时间倍率影响；使局内ui锁定60帧，减小高倍速时的性能开销"},{date="2026-01-29",author="CrazySpottedDove",message="分离boss脚本到单独文件中"},{date="2026-01-29",author="CrazySpottedDove",message="优化了boss血条的视觉效果"},{date="2026-01-30",author="CrazySpottedDove",message="修复三管加农炮特定时机学习技能协程卡死的问题；优化了三管加农炮的代码"},{date="2026-01-30",author="CrazySpottedDove",message="修正大眼的血量，使其受难度影响；使防御塔优先锁定小怪而非大眼"},{date="2026-01-30",author="CrazySpottedDove",message="使大眼单次受到600点以上伤害时飙血"},{date="2026-01-30",author="CrazySpottedDove",message="删去了多余的道具脚本与模板"},{date="2026-01-30",author="CrazySpottedDove",message="整理了game_gui中信号的注册方式"},{date="2026-01-30",author="CrazySpottedDove",message="再削一刀诡异符文"},{date="2026-01-30",author="CrazySpottedDove",message="给大眼再添加两个受击点"},{date="2026-01-30",author="CrazySpottedDove",message="使大眼不同阶段会不同次数喷发小眼睛"},{date="2026-01-30",author="CrazySpottedDove",message="为大眼添加了buff技能和恢复技能"},{date="2026-01-30",author="CrazySpottedDove",message="使用了KRA-TH的data来添加116关塔位数量；提升大眼基础生命值，并提高本关的经济产出。对大眼的一些技能效果做了平衡性调整。"},{date="2026-01-30",author="CrazySpottedDove",message="提升了大眼战役关卡的经济"}}
